const inputRows = $input.all().map(i => i.json || {});
const staticData = this.getWorkflowStaticData('global');
if (!staticData.histSignatures || typeof staticData.histSignatures !== 'object') {
  staticData.histSignatures = {};
}

function toNum(v){ const n = Number(v); return Number.isFinite(n) ? n : 0; }
function to2(v){ return Number(toNum(v).toFixed(2)); }
function nowIso(){ return new Date().toISOString(); }

const headerEstado = ['DOCUMENTO','RAZON_SOCIAL','TELEFONO','FECHA_VENCIMIENTO','SALDO_ORIGINAL','PAGO_ACUMULADO','SALDO_PENDIENTE','FECHA_ULTIMO_ABONO','STATUS_PAGO','FUENTE','LEAD_ID'];
const estadoRows = [];
const historicoRows = [];

for (const r of inputRows) {
  const documento = String(r.DOCUMENTO || '').trim();
  if (!documento) continue;
  const razon = String(r.RAZON_SOCIAL || '').trim();
  const telefono = String(r.TELEFONO || '').trim();
  const fechaV = String(r.FECHA_VENCIMIENTO || '').trim();
  const saldoOriginal = to2(r.SALDO_ORIGINAL);
  const pagoAc = to2(r.PAGO_ACUMULADO);
  const saldoPend = to2(r.SALDO_PENDIENTE);
  const fechaAb = String(r.FECHA_ULTIMO_ABONO || '').trim();
  const statusPago = String(r.STATUS_PAGO || (saldoPend <= 0 ? 'Pagado' : (pagoAc > 0 ? 'Abonado' : 'No Pagado'))).trim();
  const fuente = 'reporte_cobros';
  const leadId = String(r.LEAD_ID || '').trim();

  estadoRows.push([documento, razon, telefono, fechaV, saldoOriginal, pagoAc, saldoPend, fechaAb, statusPago, fuente, leadId]);

  const sig = [pagoAc, saldoPend, fechaAb, statusPago].join('|');
  const prev = String(staticData.histSignatures[documento] || '');
  if (sig !== prev) {
    historicoRows.push([nowIso(), documento, razon, telefono, saldoOriginal, pagoAc, saldoPend, fechaAb, statusPago, fuente, leadId]);
    staticData.histSignatures[documento] = sig;
  }
}

estadoRows.sort((a,b) => String(a[0]).localeCompare(String(b[0])));
const estadoValues = [headerEstado, ...estadoRows];

return [{ json: {
  estadoValues,
  estadoCount: estadoRows.length,
  historicoValues: historicoRows,
  historicoCount: historicoRows.length,
} }];

